const NAMESPACES: Record<string, Record<string, string>> = {
  X11, XKCD, SVGNAMES, BS381, AS2700, DVIPSNAMES,
};

let registered = false;
export function registerColors(): void {
  if (registered) return;
  registered = true;
  for (const name in CORE_COLORS) {
    registry.registerColor(name, CORE_COLORS[name]);
  }
  for (const ns in NAMESPACES) {
    const palette = NAMESPACES[ns];
    for (const key in palette) {
      registry.registerColor(`${ns}_${key}`, palette[key]);
    }
  }
}

// Register at module load (side effect).
registerColors();
